void needle_openmp_shared_1(int* referrence, int* matrix_cuda, int cols, int penalty, int i, int block_width) {
    int bx = omp_get_thread_num();
    int tx = 0; // Simulating threadIdx.x = 0 for sequential logic within block, but we need to parallelize properly

    // In OpenMP, we map blockIdx.x to a loop iteration or thread. 
    // The original CUDA code runs one block per iteration of the outer loop in runTest.
    // Here, we simulate the block logic. Since the CUDA kernel uses BLOCK_SIZE threads,
    // we will use a parallel region with BLOCK_SIZE threads to simulate one block.

    int b_index_x = bx;
    int b_index_y = i - 1 - bx;

    int index   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
    int index_n   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( 1 );
    int index_w   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( cols );
    int index_nw =  cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    // Shared arrays simulated with local arrays inside the parallel region
    // We must ensure all threads in the "block" see the same data.
    // Since OpenMP threads are global, we need to be careful. 
    // Strategy: Use a single parallel region for the whole block execution.

    // However, the calling convention in runTest loops over blocks. 
    // To preserve exact behavior, we will create a parallel region for each "block" call.

    int temp[BLOCK_SIZE+1][BLOCK_SIZE+1];
    int ref[BLOCK_SIZE][BLOCK_SIZE];

    #pragma omp parallel num_threads(BLOCK_SIZE)
    {
        int tx = omp_get_thread_num();

        if (0 == tx)
            temp[tx][0] = matrix_cuda[index_nw];

        for (int ty = 0; ty < BLOCK_SIZE; ty++)
            ref[ty][tx] = referrence[index + cols * ty];

        #pragma omp barrier

        temp[tx + 1][0] = matrix_cuda[index_w + cols * tx];

        #pragma omp barrier

        temp[0][tx + 1] = matrix_cuda[index_n];

        #pragma omp barrier

        for(int m = 0; m < BLOCK_SIZE; m++){
            if (m >= tx){
                int t_index_x = tx + 1;
                int t_index_y = m - tx + 1;
                temp[t_index_y][t_index_x] = maximum(temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                                                     temp[t_index_y][t_index_x-1] - penalty, 
                                                     temp[t_index_y-1][t_index_x] - penalty);
            }
            #pragma omp barrier
        }

        for(int m = BLOCK_SIZE - 2; 0 <= m; m--){
            if (m >= tx){
                int t_index_x = tx + BLOCK_SIZE - m;
                int t_index_y = BLOCK_SIZE - tx;
                temp[t_index_y][t_index_x] = maximum(temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                                                     temp[t_index_y][t_index_x-1] - penalty, 
                                                     temp[t_index_y-1][t_index_x] - penalty);
            }
            #pragma omp barrier
        }

        for (int ty = 0; ty < BLOCK_SIZE; ty++)
            matrix_cuda[index + ty * cols] = temp[ty+1][tx+1];
    }
}

void needle_openmp_shared_2(int* referrence, int* matrix_cuda, int cols, int penalty, int i, int block_width) {
